            member_path = os.path.normpath(member.name)
            
            if member_path.startswith('..') or member_path.startswith('/') or os.path.isabs(member_path):
                raise ValueError(f"Unsafe path in tar file: {member.name}")
            
            if '..' in pathlib.Path(member_path).parts:
                raise ValueError(f"Path traversal attempt detected: {member.name}")
            
            full_path = os.path.abspath(os.path.join(destination_dir, member_path))
            if not full_path.startswith(destination_dir):
                raise ValueError(f"Path traversal attempt detected: {member.name}")
            
